// Latch each MQTT message into flow.bms_state[bank][field] = {value, _ts}.
const parts = msg.topic.split('/');
const bank = parts[0];
const field = parts.slice(1).join('/');
if (!field) return null;  // skip bare-topic messages (no field)

const state = flow.get('bms_state') || {};
const bankState = state[bank] || {};
bankState[field] = { value: msg.payload, _ts: Date.now() };
state[bank] = bankState;
flow.set('bms_state', state);
return null;

// Run health checks per bank. Emit alert MQTT messages on state transitions
// (active / cleared) and an InfluxDB batch of important metrics every tick.
// Out 1 = alerts (one msg per transition, topic=checkbattery/alert)
// Out 2 = influx batch (single msg with payload=[points...])

const NOW = Date.now();
const NOW_ISO = new Date(NOW).toISOString();
const BANKS = ['bat_ost', 'bat_west', 'bat_big'];

const STATE = flow.get('bms_state') || {};
const HIST  = flow.get('bms_history') || {};   // bms_history[bank][code] = {since}
const PREV  = flow.get('bms_prev') || {};      // bms_prev[bank] = {uptime, cycles}

const TH = {
    cell_delta_warn:  0.050,
    cell_delta_alert: 0.100,
    cell_min:         2.80,
    cell_max:         3.60,
    cell_outlier:     0.030,
    temp_min:         -10,
    temp_max:         50,
    mosfet_temp_max:  60,
    comm_dropout_ms:  3 * 60 * 1000
};

const alerts = [];
const points = [];

function num(v) {
    if (v === undefined || v === null) return null;
    const n = parseFloat(v);
    return Number.isFinite(n) ? n : null;
}

function track(bank, code, value, severity, message) {
    const h = HIST[bank] || (HIST[bank] = {});
    if (h[code]) return;  // already active, no re-emit
    h[code] = { since: NOW_ISO };
    alerts.push({
        ts: NOW_ISO, bank, severity, code, msg: message,
        value, since: NOW_ISO, state: 'active'
    });
}

function clear(bank, code) {
    const h = HIST[bank];
    if (h && h[code]) {
        const since = h[code].since;
        delete h[code];
        alerts.push({
            ts: NOW_ISO, bank, severity: 'info', code,
            msg: 'cleared', value: null, since, state: 'cleared'
        });
    }
}

for (const bank of BANKS) {
    const s = STATE[bank];
    const get = (path) => (s && s[path]) ? num(s[path].value) : null;

    if (!s || Object.keys(s).length === 0) {
        track(bank, 'no_data', null, 'alert', 'No data ever received from bank');
        continue;
    } else {
        clear(bank, 'no_data');
    }

    // Comm dropout
    let newestTs = 0;
    for (const k in s) { if (s[k]._ts > newestTs) newestTs = s[k]._ts; }
    const ageMs = NOW - newestTs;
    if (ageMs > TH.comm_dropout_ms) {
        track(bank, 'comm_dropout', Math.round(ageMs/1000), 'alert',
            `No update in ${Math.round(ageMs/1000)}s`);
    } else {
        clear(bank, 'comm_dropout');
    }

    // Cell voltages (deltas, hard limits, per-cell outlier)
    const cellMin = get('cell_voltages/min');
    const cellMax = get('cell_voltages/max');
    const cellAvg = get('cell_voltages/average');
    const cellDelta = get('cell_voltages/delta');
    const minIdx = get('cell_voltages/min_index');
    const maxIdx = get('cell_voltages/max_index');

    if (cellDelta !== null) {
        if (cellDelta >= TH.cell_delta_alert) {
            clear(bank, 'cell_delta_warn');
            track(bank, 'cell_delta_alert', cellDelta, 'alert',
                `Cell delta ${(cellDelta*1000).toFixed(0)}mV >= ${TH.cell_delta_alert*1000}mV (cell ${maxIdx} high, cell ${minIdx} low)`);
        } else if (cellDelta >= TH.cell_delta_warn) {
            clear(bank, 'cell_delta_alert');
            track(bank, 'cell_delta_warn', cellDelta, 'warn',
                `Cell delta ${(cellDelta*1000).toFixed(0)}mV >= ${TH.cell_delta_warn*1000}mV (cell ${maxIdx} high, cell ${minIdx} low)`);
        } else {
            clear(bank, 'cell_delta_alert');
            clear(bank, 'cell_delta_warn');
        }
    }

    if (cellMin !== null && cellMin < TH.cell_min) {
        track(bank, 'cell_under', cellMin, 'alert',
            `Cell ${minIdx} at ${cellMin.toFixed(3)}V below ${TH.cell_min}V`);
    } else clear(bank, 'cell_under');

    if (cellMax !== null && cellMax > TH.cell_max) {
        track(bank, 'cell_over', cellMax, 'alert',
            `Cell ${maxIdx} at ${cellMax.toFixed(3)}V above ${TH.cell_max}V`);
    } else clear(bank, 'cell_over');

    if (cellAvg !== null) {
        for (let i = 1; i <= 16; i++) {
            const v = get('cell_voltages/' + i);
            if (v === null) continue;
            const dev = Math.abs(v - cellAvg);
            const code = 'cell_outlier_' + i;
            if (dev > TH.cell_outlier) {
                track(bank, code, v, 'warn',
                    `Cell ${i} at ${v.toFixed(3)}V deviates ${(dev*1000).toFixed(0)}mV from bank avg ${cellAvg.toFixed(3)}V`);
            } else {
                clear(bank, code);
            }
        }
    }

    // Temperatures (only sensors 1 and 2; 3 and 4 are unused per project)
    for (const i of [1, 2]) {
        const t = get('temperatures/' + i);
        if (t === null) continue;
        const codeHi = 'temp_high_' + i;
        const codeLo = 'temp_low_' + i;
        if (t > TH.temp_max) {
            clear(bank, codeLo);
            track(bank, codeHi, t, 'alert',
                `Temp sensor ${i} at ${t.toFixed(1)}°C above ${TH.temp_max}°C`);
        } else if (t < TH.temp_min) {
            clear(bank, codeHi);
            track(bank, codeLo, t, 'alert',
                `Temp sensor ${i} at ${t.toFixed(1)}°C below ${TH.temp_min}°C`);
        } else {
            clear(bank, codeHi);
            clear(bank, codeLo);
        }
    }

    const mosfetTemp = get('mosfet_status/temperature');
    if (mosfetTemp !== null && mosfetTemp > TH.mosfet_temp_max) {
        track(bank, 'mosfet_temp_high', mosfetTemp, 'alert',
            `MOSFET temp ${mosfetTemp.toFixed(1)}°C above ${TH.mosfet_temp_max}°C`);
    } else clear(bank, 'mosfet_temp_high');

    // Switch states (charge/discharge expected ON; balance is normal in either state)
    const swCharge = (s['switch/charge'] || {}).value;
    const swDisch  = (s['switch/discharge'] || {}).value;
    if (swCharge && String(swCharge) !== 'ON') {
        track(bank, 'switch_charge_off', swCharge, 'alert', `Charge switch is ${swCharge}`);
    } else clear(bank, 'switch_charge_off');
    if (swDisch && String(swDisch) !== 'ON') {
        track(bank, 'switch_discharge_off', swDisch, 'alert', `Discharge switch is ${swDisch}`);
    } else clear(bank, 'switch_discharge_off');

    // Reboot detection (uptime monotonic, allow 10s slack)
    const uptime = get('bms/uptime');
    if (uptime !== null) {
        const prevUp = (PREV[bank] || {}).uptime;
        if (prevUp !== undefined && uptime < prevUp - 10000) {
            track(bank, 'bms_reboot', uptime, 'warn',
                `BMS uptime decreased: ${prevUp}ms -> ${uptime}ms (likely reboot)`);
        } else {
            clear(bank, 'bms_reboot');
        }
        PREV[bank] = PREV[bank] || {};
        PREV[bank].uptime = uptime;
    }

    // Cycle counter monotonic
    const cycles = get('soc/num_cycles');
    if (cycles !== null) {
        const prevCyc = (PREV[bank] || {}).cycles;
        if (prevCyc !== undefined && cycles < prevCyc) {
            track(bank, 'cycles_reset', cycles, 'warn',
                `Cycle counter decreased: ${prevCyc} -> ${cycles}`);
        } else {
            clear(bank, 'cycles_reset');
        }
        PREV[bank] = PREV[bank] || {};
        PREV[bank].cycles = cycles;
    }

    // InfluxDB point: only the important values (per user)
    const fields = {};
    const map = {
        soc_percent:     'soc/soc_percent',
        total_voltage:   'soc/total_voltage',
        current:         'soc/current',
        power:           'soc/power',
        balance_current: 'soc/balance_current',
        num_cycles:      'soc/num_cycles',
        cell_delta:      'cell_voltages/delta',
        cell_min:        'cell_voltages/min',
        cell_max:        'cell_voltages/max',
        cell_avg:        'cell_voltages/average',
        capacity_ah:     'mosfet_status/capacity_ah',
        mosfet_temp:     'mosfet_status/temperature',
        temp1:           'temperatures/1',
        temp2:           'temperatures/2'
    };
    for (const fk in map) {
        const v = get(map[fk]);
        if (v !== null) fields[fk] = v;
    }
    if (Object.keys(fields).length > 0) {
        points.push({
            measurement: 'bms_health',
            tags: { bank },
            fields,
            timestamp: NOW
        });
    }
}

flow.set('bms_history', HIST);
flow.set('bms_prev', PREV);

const outAlerts = alerts.map(a => ({ topic: 'checkbattery/alert', payload: a }));
const outInflux = points.length > 0 ? { payload: points } : null;
return [outAlerts, outInflux];
